public class Average {
  public static double averageOf(int[] values) {
    int sum = 0;
    for (int v : values) sum += v;
    return sum / values.length;
  }

  public static void main(String[] args) {
    System.out.println(averageOf(new int[]{}));
  }
}

public class Copier {
  public static void main(String[] args) {
    int[] src = {3, 7, 11, 42};
    int[] dst = new int[src.length];
    for (int i = 1; i <= src.length; i++) {
      dst[i] = src[i];
    }
    for (int v : dst) System.out.println(v);
  }
}

